116	package body olo_fix_pkg is
117	
118	    function fixFmtWidthFromString (fmt : string) return natural is
119	        constant FixFmt_c : FixFormat_t := cl_fix_format_from_string(fmt);
120	    begin
121	        return cl_fix_width(FixFmt_c);
122	    end function;
123	
124	    function fixFmtWidthFromStringTolerant (fmt : string) return natural is
125	        constant FixFmt_c : FixFormat_t := fixFmtFromStringTolerant(fmt);
126	    begin
127	        return cl_fix_width(FixFmt_c);
128	    end function;
129	
130	    function fixImplementReg (
131	        logicPresent : boolean;
132	        regMode      : string) return boolean is
133	        variable Result_v : boolean := false;
134	    begin
135	
136	        -- Calculate register requirement
137	        if compareNoCase(regMode, "yes") then
138	            Result_v := true;
139	        elsif compareNoCase(regMode, "no") then
140	            Result_v := false;
141	        elsif compareNoCase(regMode, "auto") then
142	            Result_v := logicPresent;
143	        -- coverage off
144	        -- unreachable
145	        else
146	            -- synthesis translate_off
147	            assert false
148	                report errorMessage("olo_fix_pkg.fixImplementReg()", "Invalid register mode '" & regMode & "' - must be YES, NO or AUTO")
149	                severity failure;
150	            -- synthesis translate_on
151	            -- coverage on
152	        end if;
153	
154	        return Result_v;
155	
156	    end function;
157	
158	    function fixFmtFromStringTolerant (fmt : string) return FixFormat_t is
159	        type State_t is (BracketOpen_s, IntBits_s, FracBits_s, BracketClose_s, Done_s);
160	
161	        variable Result_v : FixFormat_t := FixFmt_Unused_c;
162	        variable State_v  : State_t     := BracketOpen_s;
163	    begin
164	
165	        for i in fmt'low to fmt'high loop
166	
167	            case State_v is
168	                when BracketOpen_s =>
169	                    if fmt(i) = '(' then
170	                        State_v := IntBits_s;
171	                    end if;
172	                when IntBits_s =>
173	                    if fmt(i) = ',' then
174	                        State_v := FracBits_s;
175	                    end if;
176	                when FracBits_s =>
177	                    if fmt(i) = ',' then
178	                        State_v := BracketClose_s;
179	                    end if;
180	                when BracketClose_s =>
181	                    if fmt(i) = ')' then
182	                        State_v := Done_s;
183	                    end if;
184	                when Done_s =>
185	                    null; -- unreachable
186	                -- coverage off
187	                when others =>
188	                    null; -- unreachable
189	                -- coverage on
190	            end case;
191	
192	        end loop;
193	
194	        if State_v = Done_s then
195	            Result_v := cl_fix_format_from_string(fmt);
196	        end if;
197	
198	        return Result_v;
199	    end function;
