201	    function fixDynShift (
202	        a        : std_logic_vector;
203	        aFmt     : FixFormat_t;
204	        shift    : integer;
205	        minShift : integer       := 0;
206	        maxShift : integer;
207	        rFmt     : FixFormat_t;
208	        rnd      : FixRound_t    := Trunc_s;
209	        sat      : FixSaturate_t := None_s) return std_logic_vector is
210	        -- Local declaratoins
211	        constant FullFmt_c : FixFormat_t := (max(aFmt.S, rFmt.S), max(aFmt.I+maxShift, rFmt.I), max(aFmt.F-minShift, rFmt.F+1)); -- Additional bit for rounding
212	        variable FullA_v   : std_logic_vector(cl_fix_width(FullFmt_c)-1 downto 0);
213	        variable FullOut_v : std_logic_vector(FullA_v'range);
